import { render, screen, fireEvent } from '@testing-library/react';
import '@testing-library/jest-dom';
import React from 'react';
import { Tabs, TabList, Tab, TabPanel } from './Tabs';

function TestTabs() {
  return (
    <Tabs defaultIndex={0}>
      <TabList>
        <Tab>One</Tab>
        <Tab>Two</Tab>
        <Tab>Three</Tab>
      </TabList>
      <TabPanel>Content One</TabPanel>
      <TabPanel>Content Two</TabPanel>
      <TabPanel>Content Three</TabPanel>
    </Tabs>
  );
}

describe('Compound Tabs', () => {
  it('renders the first panel by default', () => {
    render(<TestTabs />);
    expect(screen.getByTestId('panel-0')).toHaveTextContent('Content One');
    expect(screen.queryByTestId('panel-1')).not.toBeInTheDocument();
  });

  it('marks the first tab as active', () => {
    render(<TestTabs />);
    expect(screen.getByTestId('tab-0')).toHaveClass('tab--active');
    expect(screen.getByTestId('tab-1')).not.toHaveClass('tab--active');
  });

  it('switches panel on tab click', () => {
    render(<TestTabs />);
    fireEvent.click(screen.getByTestId('tab-1'));
    expect(screen.queryByTestId('panel-0')).not.toBeInTheDocument();
    expect(screen.getByTestId('panel-1')).toHaveTextContent('Content Two');
  });

  it('updates active tab class on click', () => {
    render(<TestTabs />);
    fireEvent.click(screen.getByTestId('tab-2'));
    expect(screen.getByTestId('tab-2')).toHaveClass('tab--active');
    expect(screen.getByTestId('tab-0')).not.toHaveClass('tab--active');
  });

  it('supports defaultIndex prop', () => {
    render(
      <Tabs defaultIndex={2}>
        <TabList><Tab>A</Tab><Tab>B</Tab><Tab>C</Tab></TabList>
        <TabPanel>PA</TabPanel><TabPanel>PB</TabPanel><TabPanel>PC</TabPanel>
      </Tabs>
    );
    expect(screen.getByTestId('panel-2')).toHaveTextContent('PC');
    expect(screen.getByTestId('tab-2')).toHaveClass('tab--active');
  });

  it('renders all tab labels', () => {
    render(<TestTabs />);
    expect(screen.getByTestId('tab-0')).toHaveTextContent('One');
    expect(screen.getByTestId('tab-1')).toHaveTextContent('Two');
    expect(screen.getByTestId('tab-2')).toHaveTextContent('Three');
  });
});

