import React, { createContext, useContext, useState } from 'react';
import './styles.css';

interface TabsContextType {
  activeIndex: number;
  setActiveIndex: (index: number) => void;
}

const TabsContext = createContext<TabsContextType | null>(null);

function useTabsContext() {
  const ctx = useContext(TabsContext);
  if (!ctx) throw new Error('Tabs compound components must be used within <Tabs>');
  return ctx;
}

interface TabsProps {
  children: React.ReactNode;
  defaultIndex?: number;
}

export const Tabs: React.FC<TabsProps> = ({ children, defaultIndex = 0 }) => {
  const [activeIndex, setActiveIndex] = useState(defaultIndex);

  let panelIndex = 0;
  const enhancedChildren = React.Children.map(children, child => {
    if (React.isValidElement(child) && child.type === TabPanel) {
      const idx = panelIndex++;
      return React.cloneElement(child as React.ReactElement<any>, { index: idx });
    }
    return child;
  });

  return (
    <TabsContext.Provider value={{ activeIndex, setActiveIndex }}>
      <div className="tabs">{enhancedChildren}</div>
    </TabsContext.Provider>
  );
};

interface TabListProps {
  children: React.ReactNode;
}

export const TabList: React.FC<TabListProps> = ({ children }) => {
  let tabIndex = 0;
  const enhancedChildren = React.Children.map(children, child => {
    if (React.isValidElement(child) && child.type === Tab) {
      const idx = tabIndex++;
      return React.cloneElement(child as React.ReactElement<any>, { index: idx });
    }
    return child;
  });

  return <div className="tabs__list" role="tablist">{enhancedChildren}</div>;
};

interface TabProps {
  children: React.ReactNode;
  index?: number;
}

export const Tab: React.FC<TabProps> = ({ children, index = 0 }) => {
  const { activeIndex, setActiveIndex } = useTabsContext();
  const isActive = activeIndex === index;

  return (
    <button
      data-testid={`tab-${index}`}
      className={`tabs__tab${isActive ? ' tab--active' : ''}`}
      role="tab"
      aria-selected={isActive}
      data-active={isActive ? 'true' : undefined}
      onClick={() => setActiveIndex(index)}
    >
      {children}
    </button>
  );
};

interface TabPanelProps {
  children: React.ReactNode;
  index?: number;
}

export const TabPanel: React.FC<TabPanelProps> = ({ children, index = 0 }) => {
  const { activeIndex } = useTabsContext();

  if (activeIndex !== index) return null;

  return (
    <div data-testid={`panel-${index}`} className="tabs__panel" role="tabpanel">
      {children}
    </div>
  );
};
